ast.source:
.pixel-banner-image-modal {
    max-width: 80vw;
    max-height: 90vh;
    width: 100%;
    height: auto;
    top: 50% !important;
    left: 50% !important;
    transform: translate(-50%, -50%);
}

.pixel-banner-image-view-modal {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 20px;
}

.pixel-banner-image-view-modal img {
    max-width: 100%;
    max-height: 90vh;
    object-fit: contain;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.pixel-banner-image-view-modal button {
    padding: 8px 16px;
    border-radius: 4px;
    cursor: pointer;
    transition: background-color 0.2s ease-in-out;
}

.pixel-banner-image-view-modal .image-container {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-bottom: 10px;
}

.pixel-banner-image-view-modal .image-container img,
.pixel-banner-image-view-modal .image-container video {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100%;
    max-width: 100%;
    max-height: 90vh;
    object-fit: contain;
}

.pixel-banner-image-view-modal .path-container {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-top: 10px;
    margin-bottom: 10px;
}

.pixel-banner-image-view-modal .banner-path {
    flex-grow: 1;
    margin-right: 10px;
    font-family: var(--font-monospace);
    font-size: 0.9em;
    overflow-x: auto;
    padding: 4px;
    background-color: var(--background-secondary);
    border-radius: 4px;
    word-break: break-word;
}

.pixel-banner-image-view-modal .close-button {
    margin-top: 10px;
    width: 150px;
}

